"use strict";

/* =========================================================
   Global state
========================================================= */
let horizontalScrollbar;
let docHeight, docWidth;
let miniMenuState = "0";

/* =========================================================
   Horizontal mobile menu click handling
========================================================= */
function horizontalMobileMenuClick() {
    $(".nxl-navbar li").off("click");

    $(".nxl-navbar > li:not(.nxl-caption)").on("click", function () {
        $(this).children(".nxl-submenu").removeAttr("style");

        if ($(this).hasClass("nxl-trigger")) {
            $(this).removeClass("nxl-trigger");
        } else {
            $("li.nxl-trigger").removeClass("nxl-trigger");
            $(this).addClass("nxl-trigger");
        }
    });

    $(".nxl-navbar > li:not(.nxl-caption) li").on("click", function (e) {
        e.stopPropagation();

        if ($(this).hasClass("nxl-trigger")) {
            $(this).removeClass("nxl-trigger");
        } else {
            $(this)
                .parent(".nxl-submenu")
                .find("li.nxl-trigger")
                .removeClass("nxl-trigger");

            $(this).addClass("nxl-trigger");
        }
    });
}

/* =========================================================
   Sidebar scrollbar + menu init
========================================================= */
function addScroller() {
    removeMiniMenu();
    initMenuClick();

    if ($(".navbar-content")[0]) {
        new PerfectScrollbar(".navbar-content", {
            wheelSpeed: 0.5,
            swipeEasing: false,
            suppressScrollX: true,
            wheelPropagation: true,
            minScrollbarLength: 40
        });
    }
}

/* =========================================================
   Vertical menu click handling
========================================================= */
function initMenuClick() {
    $(".nxl-navbar li").off("click");

    if ($("html").hasClass("minimenu")) return;

    $(".nxl-navbar li:not(.nxl-trigger) .nxl-submenu").slideUp();

    $(".nxl-navbar > li:not(.nxl-caption)").on("click", function () {
        if ($(this).hasClass("nxl-trigger")) {
            $(this).removeClass("nxl-trigger");
            $(this).children(".nxl-submenu").slideUp("fast");
        } else {
            $("li.nxl-trigger")
                .removeClass("nxl-trigger")
                .children(".nxl-submenu")
                .slideUp("fast");

            $(this)
                .addClass("nxl-trigger")
                .children(".nxl-submenu")
                .slideDown("fast");
        }
    });

    $(".nxl-navbar > li:not(.nxl-caption) li").on("click", function (e) {
        e.stopPropagation();

        if ($(this).hasClass("nxl-trigger")) {
            $(this).removeClass("nxl-trigger");
            $(this).children(".nxl-submenu").slideUp("fast");
        } else {
            $(this)
                .parent(".nxl-submenu")
                .find("li.nxl-trigger")
                .removeClass("nxl-trigger")
                .children(".nxl-submenu")
                .slideUp("fast");

            $(this)
                .addClass("nxl-trigger")
                .children(".nxl-submenu")
                .slideDown("fast");
        }
    });
}

/* =========================================================
   Cleanup helpers
========================================================= */
function removeDropdown() {
    $(".nxl-header:not(.nxl-mob-header) .nxl-mob-drp")
        .removeClass("mob-drp-active");
    $(".nxl-md-overlay").remove();
}

function removeHeader() {
    $(".nxl-header:not(.nxl-mob-header)")
        .removeClass("mob-header-active");
    $(".nxl-md-overlay").remove();
}

function removeMenu() {
    $(".nxl-navigation, .topbar")
        .removeClass("mob-navigation-active");
    $(".nxl-menu-overlay").remove();
}

function removeActiveStates() {
    $(".nxl-navbar li")
        .removeClass("active nxl-trigger");
    $(".dropdown, .dropdown-menu").removeClass("show");
    $(".nxl-menu-overlay").remove();
}

/* =========================================================
   Mini menu responsive behavior
========================================================= */
function removeMiniMenu() {
    const width = window.innerWidth;

    if (width <= 1024 && $("html").hasClass("minimenu")) {
        $("html").removeClass("minimenu");
        miniMenuState = "1";
    }

    if (width > 1024 && miniMenuState === "1") {
        $("html").addClass("minimenu");
        miniMenuState = "0";
    }
}

/* =========================================================
   Edge detection for flyout menus
========================================================= */
function collapseEdgeMenus() {
    if ($(window).width() <= 1024) return;

    $(".minimenu .nxl-navigation .nxl-hasmenu").hover(
        function () {
            const submenu = $(this).children(".nxl-submenu");
            const offset = submenu.offset();
            const height = submenu.outerHeight();
            const scrollTop = $(window).scrollTop();

            if (offset.top + height > window.innerHeight) {
                const maxHeight = offset.top - scrollTop;
                submenu
                    .addClass("scroll-menu")
                    .css("max-height", `calc(100vh - ${maxHeight}px)`);

                horizontalScrollbar = new PerfectScrollbar(".scroll-menu");
            }
        },
        function () {
            if (horizontalScrollbar) horizontalScrollbar.destroy();
            $(".scroll-menu").removeAttr("style").removeClass("scroll-menu");
        }
    );
}

/* =========================================================
   Document ready
========================================================= */
$(document).ready(function () {
    setTimeout(() => {
        $(".loader-bg").fadeOut("slow", function () {
            $(this).remove();
        });
    }, 400);

    if (!$("html").hasClass("nxl-horizontal")) {
        addScroller();
    }

    $(".hamburger").on("click", function () {
        $(this).toggleClass("is-active");
    });

    $("#mobile-collapse").on("click", function () {
        if (!$("html").hasClass("nxl-horizontal")) initMenuClick();

        if ($(".nxl-navigation").hasClass("mob-navigation-active")) {
            removeMenu();
        } else {
            $(".nxl-navigation")
                .addClass("mob-navigation-active")
                .append('<div class="nxl-menu-overlay"></div>');

            $(".nxl-menu-overlay").on("click", removeMenu);
        }
    });

    if ($("html").hasClass("nxl-horizontal")) {
        horizontalMobileMenuClick();
    }

    if ($("html").hasClass("minimenu")) {
        collapseEdgeMenus();
    }
});

/* =========================================================
   Window events
========================================================= */
$(window).on("resize", function () {
    if (!$("html").hasClass("nxl-horizontal")) {
        removeMiniMenu();
        initMenuClick();
    } else {
        removeActiveStates();
    }
});
